// 本地备用地址
const fallbackHosts = [
  "https://www.yck.email",
  "https://www.yck2026.top",
  "https://www.yckceo.com"
];

const KEY_WORKING_HOST = "working_host";
const KEY_HOST_EXPIRE = "host_expire";
const CACHE_TIME = 300000; // 5分钟缓存

function bhost() {
  const { java, cache } = this;
  const now = Date.now();

  // 1. 优先直接用缓存（不检测、不提示）
  const cachedHost = cache.getFromMemory(KEY_WORKING_HOST);
  const expireTime = cache.getFromMemory(KEY_HOST_EXPIRE) || 0;

  if (cachedHost != null && now < expireTime) {
    // 直接返回，不检测、不弹窗
    return cachedHost;
  }

  // ======================================================
  // 下面这段 【只有缓存过期/没有缓存时 才会执行】
  // 平时访问根本不会走到这里！
  // ======================================================
  java.toast("正在更新最优线路...");

  const goodList = checkLatency(fallbackHosts, this);
  let bestHost;

  if (goodList.length > 0) {
    bestHost = goodList[0].host;
  } else {
    bestHost = fallbackHosts[0];
  }

  // 缓存起来 5 分钟
  cache.putMemory(KEY_WORKING_HOST, bestHost);
  cache.putMemory(KEY_HOST_EXPIRE, now + CACHE_TIME);

  java.toast("线路已保存，5分钟内不再检测");
  return bestHost;
}

// 检测连通性
function isHostAvailable(host, java) {
  try {
    org.jsoup.Jsoup.connect(host)
      .method(org.jsoup.Connection.Method.HEAD)
      .timeout(2000)
      .ignoreHttpErrors(true)
      .execute();
    return true;
  } catch (e) {
    return false;
  }
}

// 批量测速
function checkLatency(urls, ctx) {
  const { java } = ctx;
  const list = [];
  for (var i = 0; i < urls.length; i++) {
    let url = urls[i].startsWith("http") ? urls[i] : "https://" + urls[i];
    try {
      var t1 = Date.now();
      org.jsoup.Jsoup.connect(url)
        .method(org.jsoup.Connection.Method.HEAD)
        .timeout(2000)
        .ignoreHttpErrors(true)
        .execute();
      var t2 = Date.now();
      list.push({ host: url, latency: t2 - t1 });
    } catch (e) {}
  }
  list.sort(function (a, b) {
    return a.latency - b.latency;
  });
  return list;
}

