let hosts = [
  "https://skybook.pages.dev",
  "https://skybook.qzz.io",
  "https://skybook.legado1.top",
  "https://skybbk1001.github.io",
];
const TIMEOUT_MS = 5000;

function probeHost(u, ctx) {
  const { java } = ctx;
  try {
    let t = Date.now();
    let resp = org.jsoup.Jsoup.connect(u + "/content.json")
      .ignoreContentType(true)
      .method(org.jsoup.Connection.Method.GET)
      .timeout(TIMEOUT_MS)
      .execute();

    let body = resp.body();
    if (!body) return null;

    JSON.parse(body);
    return { host: u, latency: Date.now() - t };
  } catch (e) {
    java.log("线路不可用: " + u + " | " + e);
    return null;
  }
}

function checkLatency(urls, ctx) {
  const { java } = ctx;
  const results = [];
  for (let i = 0; i < urls.length; i++) {
    java.toast("检测可用线路：(" + (i + 1) + "/" + urls.length + ")");
    let r = probeHost(urls[i], ctx);
    if (r) results.push(r);
  }
  results.sort((a, b) => a.latency - b.latency);
  java.longToast("检测完成：共(" + results.length + "/" + urls.length + ")个可用线路");
  return results;
}

function bhost() {
  const { source } = this;
  const cache = source.getVariable();

  try {
    if (cache) {
      let arr = JSON.parse(cache);
      if (arr && arr.length && arr[0] && arr[0].host) {
        if (probeHost(arr[0].host, this)) return arr[0].host;
      }
    }
  } catch (e) {}

  let arr = checkLatency(hosts, this);
  let best = arr.length ? arr[0].host : hosts[0];
  source.setVariable(JSON.stringify(arr.length ? arr : [{ host: best, latency: 99999 }], null, 2));
  return best;
}

