const baseApi = "https://api.lofter.com";
const ver = "product=lofter-android-8.3.20";
let s = source.getVariable();
s = /{/.test(s)?s:"";
const mockData = JSON.parse(s || '{"users":[],"collections":[],"grains":[],"tags":[]}');

// 当前数据状态
let currentData = [...mockData.users];
let currentCategory = 'user';
let remarkItemId = null;
let searchHistory = JSON.parse(source.get('lofterSearchHistory') || '[]');
let selectedItemId = null;
let isSortMode = false;

function saveDataToJson() {
    switch(currentCategory) {
        case 'user':
            mockData.users = [...currentData];
            break;
        case 'collection':
            mockData.collections = [...currentData];
            break;
        case 'grain':
            mockData.grains = [...currentData];
            break;
        case 'tag':
            mockData.tags = [...currentData];
            break;
    }
    source.putVariable(JSON.stringify(mockData));
}

//点击列表跳转对应
function handleItemClick(category, item) {
    let url,name;
    switch(category) {
        case 'user':
            run(`getUserSort("${item.name}","${item.id}");`).then(r=>java.open("sort",r));
            return;
        case 'collection':
            run(`getCollectionSort("${item.name}","${item.id}","${item.blogid}");`).then(r=>java.open("sort",r));
            return;
        case 'tag':
            run(`getTagSort("${item}");`).then(r=>java.open("sort",r));
            return;
        case 'grain':
           url = JSON.stringify({
                ["📗《"+item.name+"》"]:"https://api.lofter.com/api-grain/grain/getDetail.json?grainId="+item.id+"&offset=0"
            })
            java.open("sort", url,item.name);
            break;
    }
}

document.addEventListener('DOMContentLoaded', function() {
    renderSubscribeContent(currentCategory);
    const categoryTabs = document.querySelectorAll('.category-tab');
    categoryTabs.forEach(tab => {
        tab.addEventListener('click', function() {
            categoryTabs.forEach(t => t.classList.remove('active'));
            this.classList.add('active');
            const category = this.getAttribute('data-category');
            currentCategory = category;
            switch(category) {
                case 'user':
                    currentData = [...mockData.users];
                    break;
                case 'tag':
                    currentData = [...mockData.tags];
                    break;
                case 'grain':
                    currentData = [...mockData.grains];
                    break;
                case 'collection':
                    currentData = [...mockData.collections];
                    break;
            }
            renderSubscribeContent(category);
        });
    });

    const searchBtn = document.querySelector('.search-btn');
    searchBtn.addEventListener('click', function() {
        const searchInput = document.querySelector('.search-box input');
        const searchText = searchInput.value.toLowerCase();
        const filteredData = currentData.filter(item => 
            item.name.toLowerCase().includes(searchText) || 
            item.desc.toLowerCase().includes(searchText)
        );

        renderSubscribeList(filteredData);
    });

    const bottomButtons = document.querySelectorAll('.bottom-button');
    bottomButtons.forEach(button => {
        button.addEventListener('click', function() {
            const type = this.getAttribute('data-type');
            handleBottomButtonClick(type);
        });
    });

    const searchModal = document.getElementById('search-modal');
    const searchModalClose = document.getElementById('search-modal-close');
    const searchModalCancel = document.getElementById('search-modal-cancel');
    const searchModalConfirm = document.getElementById('search-modal-confirm');
    const searchModalInput = document.getElementById('search-modal-input');
    const searchclear = document.getElementById("search-clear")

    searchModalClose.addEventListener('click', closeModal);
    searchModalCancel.addEventListener('click', closeModal);

    searchModalConfirm.addEventListener('click', function() {
        const searchText = searchModalInput.value.trim();
        if (searchText) {
            addToSearchHistory(searchText);
            run(`getSearchSort("${searchText}")`).then(r=>java.open("sort",r))
            closeModal();
        }
    });


    const remarkModal = document.getElementById('remark-modal');
    const remarkModalClose = document.getElementById('remark-modal-close');
    const remarkModalCancel = document.getElementById('remark-modal-cancel');
    const remarkModalConfirm = document.getElementById('remark-modal-confirm');
    const remarkModalInput = document.getElementById('remark-modal-input');

    remarkModalClose.addEventListener('click', closeRemarkModal);
    remarkModalCancel.addEventListener('click', closeRemarkModal);
    remarkModalConfirm.addEventListener('click', function() {
        const remarkText = remarkModalInput.value.trim();
        if (remarkItemId) {
            updateRemarkName(remarkItemId, remarkText);
            closeRemarkModal();
        }
    });

    const contentArea = document.querySelector('.content-area');
    let startX = 0;
    let endX = 0;

    contentArea.addEventListener('touchstart', function(e) {
        startX = e.touches[0].clientX;
    }, { passive: true });

    contentArea.addEventListener('touchmove', function(e) {
        const currentX = e.touches[0].clientX;
        const diffX = currentX - startX;
    }, { passive: false });

    contentArea.addEventListener('touchend', function(e) {
        const endX = e.changedTouches[0].clientX;
        const diffX = endX - startX;
        const threshold = 50; 

        if (Math.abs(diffX) > threshold) {
            const currentTab = document.querySelector('.category-tab.active');
            const tabs = Array.from(document.querySelectorAll('.category-tab'));
            const currentIndex = tabs.indexOf(currentTab);

            if (diffX > 0 && currentIndex > 0) {
                tabs[currentIndex - 1].click();
            } else if (diffX < 0 && currentIndex < tabs.length - 1) {
                tabs[currentIndex + 1].click();
            }
        }
    }, { passive: true });
});

function getHotUrl(type){
    return `${m}/api/container/getIndex?containerid=${encodeURIComponent("106003type=25&t=3&disable_hot=1&filter_type="+type)}&title=微博热搜&show_cache_when_error=1&extparam=${encodeURIComponent("seat=1&lcate=1001&mi_cid=100103&filter_type=realtimehot&pos=0_0&c_type=30&region_relas_conf=0&dgr=0&cate=10103&display_time="+parseInt(Date.now()/1000)+"&pre_seqid="+Date.now()+"020423224")}`;
}


// 渲染订阅内容
function renderSubscribeContent(category) {
    let data = [];

    if (category === 'user') {
        data = [...mockData.users];
    } else if (category === 'tag') {
        data = [...mockData.tags];
        renderSubscribeTagList(data);
        return;
    } else if (category === 'collection') {
        data = [...mockData.collections];
    } else if (category === 'grain') {
        data = [...mockData.grains];
    }
    renderSubscribeList(data);
}


// 渲染标签列表
function renderSubscribeTagList(data){
     currentCategory = "tag";
     const subscribeList = document.getElementById('subscribe-list');
     subscribeList.innerHTML = '';

     data.forEach(x=>{
         const subscribeItem = document.createElement('div');
         subscribeItem.className = 'subscribe-tag';
         subscribeItem.innerHTML = `<span class="subscribe-tagname">${x}</span>`;
         const subscribeIdel = document.createElement('span');
         subscribeIdel.className = 'subscribe-del';
         subscribeIdel.textContent = "×";
         subscribeItem.appendChild(subscribeIdel);
         subscribeList.appendChild(subscribeItem);
     });
     const subscribeAddTag = document.createElement('div');
     subscribeAddTag.className = 'subscribe-tag';
     subscribeAddTag.innerHTML = '<span class="addtagname" contenteditable="true">输入标签</span><span class="addtag">+</span>';
     subscribeList.appendChild(subscribeAddTag);

subscribeAddTag.querySelector(".addtagname").addEventListener('blur', function() {
  const text = this.textContent.trim();
  if (!text) this.textContent = '输入标签';
});

subscribeList.querySelectorAll(".subscribe-tag").forEach(tag=>{
          tag.addEventListener('click', function(e) {
              if(!e.target.classList.contains("addtag") && !e.target.closest('.addtagname')){
                  let tagname = this.closest(".subscribe-tag").textContent.replace(/×$/g,'');
                  handleItemClick(currentCategory, tagname);
              }
      })
});

        subscribeList.querySelectorAll(".subscribe-del").forEach(x=>{
            x.addEventListener('click', function(e) {
                e.stopPropagation();
                let tagname = this.closest(".subscribe-tag").textContent.replace(/×$/g,'');
                if(confirm("确定要删除【"+tagname+"】这个标签吗？")){
                    const index = data.findIndex(item =>item === tagname);
                    if (index !== -1) {
                        data.splice(index, 1);
                        currentData = data; 
                        renderSubscribeTagList(currentData);
                        saveDataToJson();
                        java.toast(`已删除标签: ${tagname}`);
                       } else {
                           java.toast(`未找到标签: ${tagname}`);
                       }
                    }
                 })
        })


        subscribeList.querySelector(".addtag").addEventListener('click', function(e) {
            e.stopPropagation();
            let name = document.querySelector(".addtagname").textContent;
            if(name.trim()){
                if(data.indexOf(name) === -1) {
                    data.push(name);
                    currentData = data; 
                    renderSubscribeTagList(currentData);
                    saveDataToJson();
                    java.toast("添加成功");
                 } else {
                     java.toast("已存在相同标签");
                   }
                 }
              });
}

// 渲染订阅列表
function renderSubscribeList(data) {
    const subscribeList = document.getElementById('subscribe-list');
    subscribeList.innerHTML = '';

    data.forEach((item, index) => {
        const subscribeItem = document.createElement('div');
        subscribeItem.className = 'subscribe-item';
        subscribeItem.setAttribute('data-id', item.id);
        subscribeItem.setAttribute('data-index', index);
        const avatarContent = item.avatar ? 
            `<img src="${item.avatar}" alt="${item.name}">` : 
            item.name.charAt(0);

        const displayName = item.remarkName ?(item.name + " ("+item.remarkName+")"):item.name;

        subscribeItem.innerHTML = `
            <div class="subscribe-avatar">${avatarContent}</div>
            <div class="subscribe-details">
                <div class="subscribe-title">${displayName}</div>
                <div class="subscribe-desc">${item.desc}</div>
            </div>
            <div class="subscribe-actions">
                <button class="subscribe-action delete" data-action="delete" title="删除">❎</button>
                <button class="subscribe-action remark" data-action="remark" title="设置备注">🆔</button>
                <button class="subscribe-action sort" data-action="sort" title="排序">↕️</button>
            </div>
        `;

        if (isSortMode) {
            const swapButton = document.createElement('button');
            swapButton.className = 'subscribe-action swap';
            swapButton.setAttribute('data-action', 'swap');
            swapButton.setAttribute('title', '交换位置');
            swapButton.textContent = '⇄';
            subscribeItem.querySelector('.subscribe-actions').appendChild(swapButton);

            if (item.id === selectedItemId) {
                subscribeItem.classList.add('selected');
            }
        }

        subscribeList.appendChild(subscribeItem);
    });

    bindSubscribeActions();
    if (!isSortMode) {
        bindItemClickEvents();
    }
}

function bindItemClickEvents() {
    const subscribeItems = document.querySelectorAll('.subscribe-item');

    subscribeItems.forEach(item => {
        item.addEventListener('click', function(e) {
            if (e.target.classList.contains('subscribe-action')) {
                return;
            }

            const itemId = this.getAttribute('data-id');
            const currentItem = currentData.find(item => item.id === itemId);

            if (currentItem) {
                handleItemClick(currentCategory, currentItem);
            }
        });
    });
}

function bindSubscribeActions() {
    const deleteButtons = document.querySelectorAll('.subscribe-action.delete');
    const remarkButtons = document.querySelectorAll('.subscribe-action.remark');
    const sortButtons = document.querySelectorAll('.subscribe-action.sort');
    const swapButtons = document.querySelectorAll('.subscribe-action.swap');
    const subscribeItems = document.querySelectorAll('.subscribe-item');
    deleteButtons.forEach(button => {
        button.addEventListener('click', function(e) {
            e.stopPropagation();
            const itemElement = this.closest('.subscribe-item');
            const itemId = itemElement.getAttribute('data-id')
            if (confirm('确定要删除这个订阅吗？')) {
                deleteSubscribeItem(itemId);
            }
        });
    });

    remarkButtons.forEach(button => {
        button.addEventListener('click', function(e) {
            e.stopPropagation();
            const itemElement = this.closest('.subscribe-item');
            const itemId = itemElement.getAttribute('data-id');
            const currentName = itemElement.querySelector('.subscribe-title').textContent

            openRemarkModal(itemId, currentName);
        });
    });

    sortButtons.forEach(button => {
        button.addEventListener('click', function(e) {
            e.stopPropagation();
            toggleSortMode();
        });
    });

    swapButtons.forEach(button => {
        button.addEventListener('click', function(e) {
            e.stopPropagation();
            const itemElement = this.closest('.subscribe-item');
            const itemId = itemElement.getAttribute('data-id');

            handleSwapItem(itemId);
        });
    });

    if (isSortMode) {
        subscribeItems.forEach(item => {
            item.addEventListener('click', function(e) {
                if (e.target.classList.contains('subscribe-action')) return;

                const itemId = this.getAttribute('data-id');
                handleSelectItem(itemId);
            });
        });
    }
}

function toggleSortMode() {
    isSortMode = !isSortMode;
    selectedItemId = null;

    if (isSortMode) {
        alert('已进入排序模式，请先点击要移动的项目，再点击目标项目的交换按钮');
    } else {
        alert('已退出排序模式');
    }

    renderSubscribeList(currentData);
}

function handleSelectItem(itemId) {
    if (!isSortMode) return;

    selectedItemId = itemId;

    renderSubscribeList(currentData);
}

function handleSwapItem(targetItemId) {
    if (!isSortMode || !selectedItemId) {
        alert('请先选择要移动的项目');
        return;
    }

    if (selectedItemId === targetItemId) {
        alert('不能与自己交换位置');
        return;
    }

    const selectedIndex = currentData.findIndex(item => item.id === selectedItemId);
    const targetIndex = currentData.findIndex(item => item.id === targetItemId);

    if (selectedIndex === -1 || targetIndex === -1) return;

    [currentData[selectedIndex], currentData[targetIndex]] = 
        [currentData[targetIndex], currentData[selectedIndex]];

    selectedItemId = null;
    renderSubscribeList(currentData);
    saveDataToJson();
}


function deleteSubscribeItem(itemId) {
    currentData = currentData.filter(item => item.id !== itemId);
    renderSubscribeList(currentData);
    saveDataToJson();
}

function openRemarkModal(itemId, currentName) {
    remarkItemId = itemId;
    const remarkModal = document.getElementById('remark-modal');
    const remarkModalInput = document.getElementById('remark-modal-input');

    remarkModalInput.value = currentName;
    remarkModal.classList.add('active');
    remarkModalInput.focus();
}

function closeRemarkModal() {
    const remarkModal = document.getElementById('remark-modal');
    const remarkModalInput = document.getElementById('remark-modal-input');

    remarkModal.classList.remove('active');
    remarkModalInput.value = '';
    remarkItemId = null;
}

function updateRemarkName(itemId, remarkName) {
    const itemIndex = currentData.findIndex(item => item.id === itemId);
    if (itemIndex !== -1) {
        currentData[itemIndex].remarkName = remarkName;
    }

    renderSubscribeList(currentData);
    saveDataToJson();
}

function handleBottomButtonClick(type) {
    switch (type) {
        case 'search':
            const searchModal = document.getElementById('search-modal');
            searchModal.classList.add('active');
            document.getElementById('search-modal-input').focus();
