                "热门影视榜":"https://api.lofter.com/newapi/hotsearch/ranklist.json?"+ver+"&t=4",
                "二次元创作榜单":"https://api.lofter.com/newapi/hotsearch/ranklist.json?"+ver+"&t=5"
            });
            java.open("sort", url)
            break;
        case 'hotlist':
            url = JSON.stringify({
