                "文学":`${baseApi}/recommend/domainPosts.json?${ver},{"method":"POST","body":"domainId=1538118079721&offset=0&feedTime=0&count=0"}`,
                "绘画":`${baseApi}/recommend/domainPosts.json?${ver},{"method":"POST","body":"domainId=1370406202794&offset=0&feedTime=0&count=0"}`,
                "影视":`${baseApi}/recommend/domainPosts.json?${ver},{"method":"POST","body":"domainId=1442207751226&offset=0&feedTime=0&count=0"}`,
                "二次元":`${baseApi}/recommend/domainPosts.json?${ver},{"method":"POST","body":"domainId=1370406175120&offset=0&feedTime=0&count=0"}`,
                "乙游":`${baseApi}/recommend/domainPosts.json?${ver},{"method":"POST","body":"domainId=18244400&offset=0&feedTime=0&count=0"}`,
                "娱乐":`${baseApi}/recommend/domainPosts.json?${ver},{"method":"POST","body":"domainId=1430907486999&offset=0&feedTime=0&count=0"}`,
