function renderSearchHistory() {
    const searchHistoryList = document.getElementById('search-history-list');
    searchHistoryList.innerHTML = '';

    if (searchHistory.length === 0) {
        searchHistoryList.innerHTML = '<div style="color: #999; font-size: 14px;">暂无搜索历史</div>';
        return;
    }

    const recentHistory = searchHistory.slice(-10).reverse();

    recentHistory.forEach(item => {
        const historyItem = document.createElement('div');
        historyItem.className = 'search-history-item';
        historyItem.textContent = item;

        historyItem.addEventListener('click', function() {
            document.getElementById('search-modal-input').value = item;
        });

        searchHistoryList.appendChild(historyItem);
    });
}

document.addEventListener('DOMContentLoaded', function() {
            const clearButton = document.querySelector('.search-clear');
            if (clearButton) {
                clearButton.addEventListener('click', function() {
                    source.put('lofterSearchHistory', '');
                    searchHistory = [];
                    renderSearchHistory()
                });
            }
        });

function addToSearchHistory(searchText) {

    searchHistory = searchHistory.filter(item => item !== searchText);
    searchHistory.push(searchText);
    if (searchHistory.length > 50) {
        searchHistory = searchHistory.slice(-50);
    }
    source.put('lofterSearchHistory', JSON.stringify(searchHistory));
}

function closeModal() {
    document.getElementById('search-modal').classList.remove('active');
    document.getElementById('search-modal-input').value = '';
    document.getElementById('login-modal').classList.remove('active');
}

