    // 定义去广告的函数
    function removeAds() {
        // 例子：通过 class 名称移除广告
        const adClasses = ['ad-banner', 'ad-container', 'ad-sidebar', 'popup-ad']; // 替换为实际广告的 class 名
        adClasses.forEach(className => {
            const ads = document.querySelectorAll(`.${className}`);
            ads.forEach(ad => ad.remove());
        });

        // 例子：通过 id 移除广告
        const adIds = ['watch-footer', 'mobile-ad', 'interstitial-ad']; // 替换为实际广告的 id 名
        adIds.forEach(id => {
            const ad = document.getElementById(id);
            if (ad) ad.remove();
        });

        // 例子：移除某些广告标签（比如 iframe 广告）
        const adTags = ['iframe', 'ins']; // 替换为常用的广告标签
        adTags.forEach(tag => {
            const ads = document.querySelectorAll(tag);
            ads.forEach(ad => {
                if (ad.src && ad.src.includes('ads')) { // 检查 URL 中是否包含 "ads"
                    ad.remove();
                }
            });
        });
    }


document.addEventListener('DOMContentLoaded', function() {
