        'h1, h2, h3, h4',
        '[class*="title"]',
        '[class*="name"]'
    ];

    for (const selector of selectors) {
        const titleElement = element.closest(selector) || 
                           element.querySelector(selector) || 
                           element.parentElement?.querySelector(selector);

        if (titleElement && titleElement.textContent && titleElement.textContent.trim()) {
            return titleElement.textContent.trim();
        }
    }

    // 最后尝试从元素文本本身获取
    return element.textContent?.trim() || 
           element.parentElement?.textContent?.trim() || 
           '未知书名';
}
// 拦截导航
function interceptNavigation(event) {
    event.preventDefault();
    event.stopPropagation();
    event.stopImmediatePropagation();

    let targetUrl = '';
    const element = event.currentTarget;

    // 1. 处理a标签
    if (element.tagName.toLowerCase() === 'a' && element.href) {
        targetUrl = element.href;
    }
    // 2. 处理带onclick的元素
    else if (element.onclick || element.getAttribute('onclick')) {
        const onclickValue = element.onclick?.toString() || element.getAttribute('onclick');
        const urlMatch = onclickValue.match(/window\.location\.href\s*=\s*['"]([^'"]+)['"]/);
        if (urlMatch) {
            targetUrl = urlMatch[1];
        }
    }

    if (!targetUrl) {
        console.warn('未找到跳转URL');
        return true;
    }

    // 构建最终URL
    let finalUrl = targetUrl;

    // 检查是否为huanmengacg域名
    if (host.includes('huanmengacg')) {
        const bookName = getBookName(element);

        // 添加书名查询参数和##分隔符后的书名（不进行编码）
        const separator = finalUrl.includes('?') ? '&' : '?';
        finalUrl = `${finalUrl}${separator}book_name=${bookName}##${bookName}`;

        console.log('添加书名的URL:', finalUrl);
    }

    // 跳转到处理后的URL
    window.location.href = finalUrl;

    return false;
}

// 为现有元素添加拦截
function addInterceptors() {
    // 1. 拦截所有a标签
    document.querySelectorAll('a[href]').forEach(link => {
        // 避免重复绑定
        if (!link.hasAttribute('data-intercept-bound')) {
            link.addEventListener('click', interceptNavigation, true);
            link.setAttribute('data-intercept-bound', 'true');
        }
    });

    // 2. 拦截特定卡片类型
    const cardSelectors = [
        '.book-card[onclick]', 
        'div[onclick*="window.location.href"]', 
        'li[onclick*="window.location.href"]',
        'section[onclick*="window.location.href"]',
        '.details-part' // 添加您提供的示例中的类
    ];

    cardSelectors.forEach(selector => {
        document.querySelectorAll(selector).forEach(card => {
            if (!card.hasAttribute('data-intercept-bound')) {
                card.addEventListener('click', interceptNavigation, true);
                card.setAttribute('data-intercept-bound', 'true');
            }
        });
    });
}

// 使用MutationObserver监控DOM变化
const observer = new MutationObserver(function(mutations) {
    mutations.forEach(() => {
        addInterceptors(); // DOM变化时重新绑定拦截器
    });
});

// 开始观察文档
observer.observe(document.body, {
    childList: true,    // 监控子节点变化
    subtree: true,      // 监控所有后代节点
    attributes: true,   // 监控属性变化
    attributeFilter: ['onclick', 'href', 'class'] // 只监控这些属性
});

// 初始执行一次拦截器绑定
addInterceptors();
showNotification('拦截器成功启动！');

function showNotification(message, type = 'success', duration = 2000) {
    // 创建样式（如果不存在）
    if (!document.getElementById('notification-styles')) {
        const style = document.createElement('style');
        style.id = 'notification-styles';
        style.textContent = `
            .notification {
                position: fixed;
                top: 20px;
                right: 20px;
                padding: 15px 25px;
                color: white;
                border-radius: 8px;
                box-shadow: 0 4px 15px rgba(0, 0, 0, 0.1);
                display: flex;
                align-items: center;
                transform: translateX(150%);
                opacity: 0;
                transition: all 0.3s ease;
                z-index: 1000;
                font-family: 'Arial', sans-serif;
            }

            .notification.show {
                transform: translateX(0);
                opacity: 1;
            }

            .notification.hide {
                transform: translateX(150%);
                opacity: 0;
            }

            .notification-icon {
                margin-right: 10px;
                font-size: 20px;
            }

            .notification-content {
                font-size: 16px;
            }

            .notification.success {
                background-color: #4CAF50;
            }

            .notification.error {
                background-color: #f44336;
            }

            .notification.warning {
                background-color: #ff9800;
            }

            .notification.info {
                background-color: #2196F3;
            }
        `;
        document.head.appendChild(style);
    }

    // 创建通知元素
    const notification = document.createElement('div');
    notification.className = `notification ${type}`;

    // 添加图标
    const icon = document.createElement('span');
    icon.className = 'notification-icon';

    // 根据类型设置不同图标
    const icons = {
        success: '✓',
        error: '✕',
        warning: '⚠',
        info: 'ℹ'
    };
    icon.textContent = icons[type] || '✓';

    // 添加消息内容
    const content = document.createElement('span');
    content.className = 'notification-content';
    content.textContent = message;

    // 组装通知
    notification.appendChild(icon);
    notification.appendChild(content);

    // 添加到body
    document.body.appendChild(notification);

    // 显示通知
    setTimeout(() => {
        notification.classList.add('show');
    }, 10);

    // 指定时间后隐藏并移除通知
    setTimeout(() => {
        notification.classList.remove('show');
        notification.classList.add('hide');

        // 动画结束后移除元素
        notification.addEventListener('transitionend', () => {
            notification.remove();
        });
    }, duration);
}

