var doc = org.jsoup.Jsoup.parse(result);
var myImgs = [];

// 1. 严格锁定正文 ID，彻底避开 Related Posts 等外部组件
var contentHtml = "";
var mainBox = doc.getElementById("brxe-qoenez");
if (mainBox) {
    contentHtml = mainBox.html();
} else {
    contentHtml = doc.select(".brxe-post-content").html();
}

if (contentHtml) {
    // 2. 在限定范围内扫描高清图片链接
    var regex = /https?:\/\/qikzj\.com\/wp-content\/uploads\/[^"'\s<>]*?\.(?:jpg|jpeg|png|webp|gif)/gi;
    var matches;
    while ((matches = regex.exec(contentHtml)) !== null) {
        var s = matches[0];
        // 过滤 Logo 和头像
        if (s.indexOf("logo") === -1 && s.indexOf("avatar") === -1) {
            // 还原高清原图路径，去掉尺寸和缩放后缀
            var cleanUrl = s.replace(/-\d+x\d+\./i, ".").replace(/-scaled\./i, ".");
            if (myImgs.indexOf(cleanUrl) === -1) {
                myImgs.push(cleanUrl);
            }
        }
    }
}

var displayTitle = (typeof title !== 'undefined' && title) ? title : "QikZ Visuals";

