let urls = [];
let resultStr = String(result);

let getM3u8 = (html = resultStr) => {
    let url = /(https?:[^'"\s]*?\.m3u8[^'"\s]*)/g;
    let urlSet = new Set();
    for (let match of (html.matchAll(url) || [])) {
  	   let ul = match[1].replace(/\\/g, "");
  	   urlSet.add(ul);
    	};
    return Array.from(urlSet);
};

 let updateProgress = (current, total) => {
    let percentage = Math.round(current / total * 10000)/100;
    let blocks = Math.floor(percentage / 10);
    let progressBar = "█".repeat(blocks) + "░".repeat(10 - blocks);
    java.longToast(`【加载进度】\n${progressBar} \n${percentage}%`);
};

if (/点我/.test(result) && /查看详情/.test(result)) {
    let list = java.getElements('@@#post>article>.post-content>p>a');
    let links = Array.from(list).slice(0,-1);
    let tempUrls = []; 
    links.forEach((link, index) => {
        updateProgress(index + 1, links.length);

        let href = String(link.attr('href'));
        let fullUrl = `${source.key}${href}`;
        let doc = String(java.ajax(fullUrl));
        let pageUrls = getM3u8(doc);
        if (pageUrls.length > 0) {
            tempUrls = tempUrls.concat(pageUrls);
        }
        if (index === links.length - 1) {
            urls = tempUrls;
        }
    })
} else {
    urls = getM3u8();
};

`<html>
