function setupCustomPlayer(video) {
  // 手势滑动快进
  let isDragging = false;
  let startX = 0;
  let startTime = 0;

  // 长按加速相关变量
  let longPressTimer = null;
  const LONG_PRESS_DELAY = 300;
  const NORMAL_SPEED = 1.25;
  const FAST_SPEED = 3;
  let wasPaused = false;
  // 触摸事件处理
  function handleTouchStart(e) {
startX = e.touches[0].clientX;
startTime = video.currentTime;
wasPaused = video.paused;
longPressTimer = setTimeout(() => {
  video.playbackRate = FAST_SPEED;
  if (wasPaused) video.play();
}, LONG_PRESS_DELAY);
  }
  function handleTouchMove(e) {
if (longPressTimer) {
  clearTimeout(longPressTimer);
  longPressTimer = null;
}
const dx = e.touches[0].clientX - startX;
if (Math.abs(dx) > 10) {
  if (!isDragging) {
video.pause();
isDragging = true;
  }
  const change = (dx / video.clientWidth) * video.duration;
  video.currentTime = Math.max(0, Math.min(startTime + change, video.duration));
}
  }
  function handleTouchEnd() {
if (longPressTimer) {
  clearTimeout(longPressTimer);
  longPressTimer = null;
}
if (isDragging) {
  video.playbackRate = NORMAL_SPEED;
  video.play();
  isDragging = false;
} else if (video.playbackRate === FAST_SPEED) {
  video.playbackRate = NORMAL_SPEED;
  if (wasPaused) video.pause();
}
  }
  // 添加触摸事件监听
  video.addEventListener('touchstart', handleTouchStart);
  video.addEventListener('touchmove', handleTouchMove);
  video.addEventListener('touchend', handleTouchEnd);

  // 初始播放速度
  video.playbackRate = NORMAL_SPEED;
  // 创建按钮的通用函数
  function createButton(text, onClick, position, width = '20px') {
const button = document.createElement('button');
button.textContent = text;
button.style.position = 'absolute';
button.style[position.horizontal] = '0';
button.style.top = '50%';
button.style.transform = 'translateY(-50%)';
button.style.zIndex = '999';
button.style.padding = '1px';
button.style.background = 'rgba(51, 51, 51, 0)';
button.style.color = '#fff';
button.style.border = 'none';
button.style.cursor = 'pointer';
button.style.width = width;
button.style.height = '30px';
button.addEventListener('click', onClick);
video.parentNode.appendChild(button);
return button;
  }
  // 旋转按钮（右侧）
  createButton('⟳', () => {
const currentRotation = parseInt(video.getAttribute('data-rotation') || '0');
const newRotation = (currentRotation + 90) % 360;
video.setAttribute('data-rotation', newRotation);
// 保留当前的缩放比例
const currentTransform = video.style.transform || '';
let currentScale = 1;
const scaleMatch = currentTransform.match(/scale\(([^)]+)\)/);
if (scaleMatch) currentScale = parseFloat(scaleMatch[1]);
video.style.transform = `rotate(${newRotation}deg) scale(${currentScale})`;
  }, { horizontal: 'right' });
  // 缩放按钮（左侧）
  let zoomCount = 0;
  createButton('+', () => {
const currentRotation = parseInt(video.getAttribute('data-rotation') || '0');
// 获取当前缩放比例
const currentTransform = video.style.transform || '';
let currentScale = 1;
const scaleMatch = currentTransform.match(/scale\(([^)]+)\)/);
if (scaleMatch) currentScale = parseFloat(scaleMatch[1]);
if (zoomCount < 4) {
  const newScale = currentScale * 1.25;
  video.style.transform = `rotate(${currentRotation}deg) scale(${newScale})`;
  zoomCount++;
} else {
  video.style.transform = `rotate(${currentRotation}deg) scale(1)`;
  zoomCount = 0;
}
  }, { horizontal: 'left' });
  // 快速跳转按钮（底部中央）
  const buttonContainer = document.createElement('div');
  buttonContainer.style.position = 'absolute';
  buttonContainer.style.bottom = '0';
  buttonContainer.style.left = '50%';
  buttonContainer.style.transform = 'translateX(-50%)';
  buttonContainer.style.display = 'flex';
  buttonContainer.style.gap = '10px';
  buttonContainer.style.zIndex = '999';

  // 按钮配置
  const seekButtons = [
{ text: '-5分', time: -300 },
{ text: '-1分', time: -60 },
{ text: '+1分', time: 60 },
{ text: '+5分', time: 300 }
  ];
  seekButtons.forEach(({ text, time }) => {
const button = document.createElement('button');
button.textContent = text;
button.style.padding = '1px';
button.style.background = 'rgba(51, 51, 51, 0)';
button.style.color = '#fff';
button.style.border = 'none';
button.style.cursor = 'pointer';
button.style.width = '60px';
button.style.height = '30px';
button.addEventListener('click', () => {
  video.currentTime = Math.max(0, Math.min(video.currentTime + time, video.duration));
});
buttonContainer.appendChild(button);
  });
  video.parentNode.appendChild(buttonContainer);
}
// 修改初始化逻辑，增加重试机制
function initPlayerWithRetry() {
  const maxRetries = 10;
  const retryInterval = 500;
  let retries = 0;
  const tryInit = () => {
const video = document.getElementById('video');
if (video) {
  setupCustomPlayer(video);
} else if (retries < maxRetries) {
  retries++;
  setTimeout(tryInit, retryInterval);
}
  };
  tryInit();
}
// 使用重试机制初始化播放器
initPlayerWithRetry();

