coverDecodeJs:
function toByteArray(input) {
  var out = new Packages.java.io.ByteArrayOutputStream();
  var buffer = java.strToBytes('\0'.repeat(4096));
  var bytesRead;
  while ((bytesRead = input.read(buffer)) != -1) {
    out.write(buffer, 0, bytesRead);
  }
  return out.toByteArray();
}

(function() {
  // 1. 读取原始字节内容
  var textBytes = toByteArray(result);
  // 2. 如果是GIF文件，直接返回原始字节
  if (src.endsWith('.gif')) {
    return textBytes;
  }
  try {
    // 3. 将字节转换为字符串（用于解析数据URI）
    var dataUri = java.bytesToStr(textBytes, "UTF-8");
    // 4. 判断是完整的数据URI还是纯Base64数据
    var base64Prefix = "base64,";
    var base64Index = dataUri.indexOf(base64Prefix);
    if (base64Index === -1) {
      // 如果没有找到base64前缀，检查是否需要截取第一个/及之后的内容
      var firstSlashIndex = dataUri.indexOf('/');
      if (firstSlashIndex !== -1) {
        // 如果找到第一个/，截取/及之后的内容
        dataUri = dataUri.substring(firstSlashIndex);
      }
      // 对整个内容进行Base64解码
      return java.base64DecodeToByteArray(dataUri);
    } else {
      // 如果是标准data URI，提取base64编码部分解码
      var base64Data = dataUri.substring(base64Index + base64Prefix.length);
      return java.base64DecodeToByteArray(base64Data);
    }
  } catch (e) {
    // 解码失败时返回原始字节
    return textBytes;
  }
})();

