function getBooklist(list,src){
    let html="";
    let alllist = list.recommend_novelinfo ?? list;
    let json = src?JSON.parse(src):{};
    json = json?.data?.booklist_desc ?? {}
    for(let i in alllist){
        let $ = alllist[i];
        let novelid = $.novelid;
        let cover = ($.cover || ("https://i9-static.jjwxc.net/novelimage.php?novelid="+novelid)).replace(/https?/,'https');
        let cover2 = "https://i9-static.jjwxc.net/novelimage.php?novelid="+novelid;
        let novelname = $.novelname;
        let authorname = $.authorname;
        let novelstep_name = $.novelstep_name || $.novelstep_str || $.novelstep;
        let novelsize = $.novelsize;
        let novel_review_score = $.novel_review_score || ($.fav_count_str==undefined?"":$.fav_count_str+"收藏");
        let novelstar = $.novelstar || 0;
        let s="";
        for(i=0;i<novelstar;i++){s+="★"}
        novelstar=s;
        let novelintroshort = $.novelintroshort;
        let comment = $.comment || $.commentbody || "";
        comment = this.replaceEmoticons(comment? comment.replace(/\s*(.*)\n/g,'&emsp;&emsp;$1<br>').replace(/<br>(?!&emsp)/gm,'<br>&emsp;&emsp;').replace(/null/g,''):"");
        let novelclass_str = $.novelclass_str || ("第"+$.chapterid+"章  打分："+$.commentmark+"分  订阅率："+($?.subscription_rate_info?.rate??"")+($?.subscription_rate_info?.iconapp=="rate_novelallbuy"?"100%":""));
        novelclass_str = novelclass_str.replace(/订阅率：$/,'');
        let onclickOpen = json.reader_name?` onclick="openS('${json.reader_name}','${json.readerid}')"`:"";

        html +=`
            <div class="book">
                <div class="bookdes">
                 <div class="pic" onclick="addShelf('${novelid}')" href="javascript:;">
                     <img src="${cover}" referrerpolicy="no-referrer" onerror="if(this.src!='${cover2}')this.src='${cover2}'">
                 </div>
                 <div class="details>
                      <p class="bookname">
                          <span class="name">
                             <a href ="https://m.jjwxc.net/book2/${novelid}">${novelname}</a>
                          </span>
                          <br>
                          <span class="author" onclick="window.open('https://m.jjwxc.net#bookAuthor=${authorname}')">
                             ——${authorname}
                          </span>
                      </p>    
                      <p class="tag" onclick="window.open('https://m.jjwxc.net#bookName=${novelname}')">
                      <br>
                      ${novelsize}•${novelstep_name}•${novel_review_score} 🔎<br><br>
                        ${novelintroshort}<br><br>
                        ${novelclass_str}<br><br>
                        ${novelstar}
                      </p>             
                 </div>             
                 </div>
                     ${comment ? `<div class="comment" style="margin-top:1px"${onclickOpen}>`+comment+"</div>":""}
            </div>     
            `;                
    }
    let floor_reply_all = list.floor_reply_all ?? [];
    let floor_reply_html = "";
    floor_reply_all.forEach(x=>{
         let onclickOpen = ` onclick="openS('${x.nickname}','${x.readerid}')"`
        floor_reply_html += `<span style="color:#3A9DBF"${onclickOpen}>${x.nickname}：</span>${x.body}<br>`;
      });
   if(floor_reply_all.length)floor_reply_html =  `<div class="comment" style="background:#eee">${floor_reply_html}</div>`;
    return this.replaceEmoticons(html+floor_reply_html)
   }



