      <button id="viewBooklistBtn" style="padding: 12px 20px; background-color: white; border: 1px solid #e6f0fa; border-radius: 4px; color: #4a89dc; font-weight: 500;cursor: pointer; font-size: 14px; transition: background-color 0.2s;">📚查看书单</button>
    </div>
