<js>

try{
   list = JSON.parse(src).data?.novel_lists || JSON.parse(src).data?.booklist_desc?.recommend_novelinfo || JSON.parse(src).data;

   html = result + '<div class="booklists">'+getBooklist(list,src)+'</div>';
   result = String(html)
     .replace(/<div class="comment">\s*<\/div>|<span class="level">\s*&emsp;级&emsp;\s*<\/span>/g,'')
     .replace(/荐书描述 共本/,'');
   result = replaceEmoticons(result);
   result = /subjectDetail/.test(baseUrl)?result.replace(/荐书描述 共\d+本/,'找书描述'):result;
   result += `
<script>
function openS(name,id){
        java.getThemeConfig();
        let modalOverlay = document.querySelector("#modalOverlay");
        modalOverlay.style.display = "flex";
        document.querySelector(".modalName").textContent = name;
        modalOverlay.addEventListener('click', () => {
            modalOverlay.style.display = 'none';
        });

        document.querySelector("#viewCommentsBtn").addEventListener('click', () => {
            let url = "https://android.jjwxc.net/app.jjwxc/android/reading/comment/getTopTenNovelComment?versionCode=477&reader_id="+id+"&useridentity_check=1";
            java.open("rss",url,name+"的评论","📖晋江书单");
        });

        document.querySelector("#viewBooklistBtn").addEventListener('click', () => {
            let url = "https://android.jjwxc.net/app.jjwxc/android/reading/booklist/get?versionCode=477&reader_id="+id+"&type=all";
            java.open("sort",url,name+"的书单","📖晋江书单");
        });
}

 var replyManager = {
        listid: 0,
        currentPage: 0,
        totalPages: 0,
        isLoading: false,
        isInitialized: false
    };


    function getListIdFromUrl() {
        var url = window.location.href;
        var match = url.match(/id=(\\d+)/);
        return match ? match[1] : 0;
    }


    ${getBooklist.toString().replace(/this\./g,'')}
    ${replaceEmoticons.toString()}

    function fetchWithHeaders(url, options) {
        var defaultHeaders = {
            "referer": "https://android.jjwxc.net/?v=357",
            "versionCode": "357",
            "versiontype": "reading",
            "User-Agent": "Dalvik/2.1.0"
        };
        var fetchOptions = options || {};
        fetchOptions.headers = Object.assign({}, defaultHeaders, fetchOptions.headers || {});
        if (!fetchOptions.headers.referer) {
            fetchOptions.headers.referer = defaultHeaders.referer;
        }
        return fetch(url, fetchOptions);
    }

    function loadReplies(page) {
        if (replyManager.isLoading) {
            return;
        }

        replyManager.isLoading = true;
        if (page === 1) {
            var loadingIndicator = document.getElementById('loadingIndicator');
            if (loadingIndicator) loadingIndicator.classList.remove('hidden');
        } else {
            var loadMoreBtn = document.getElementById('loadMore');
            var loadingIndicator = document.getElementById('loadingIndicator');
            if (loadMoreBtn) loadMoreBtn.classList.add('hidden');
            if (loadingIndicator) loadingIndicator.classList.remove('hidden');
        }

        var listid = getListIdFromUrl();
        if (!listid) {
            console.error("无法获取列表ID");
            showError("加载失败：无法获取列表ID");
            return;
        }

        var reply_url = "https://app.jjwxc.org/app.jjwxc/android/reading/BookListFindBook/replyList?versionCode=357&listid=" + listid + "&page=" + page + "&filter_recommend=0";

        fetchWithHeaders(reply_url)
            .then(function(response) {
                if (!response.ok) {
                    throw new Error('网络请求失败: ' + response.status);
                }
                return response.text();
            })
            .then(function(text) {
                try {
                    var responseData = JSON.parse(text);


                    var booklistsContainer = document.querySelector('.booklists');


                    if (responseData.data && responseData.data.data && Array.isArray(responseData.data.data)) {
                        var replies = responseData.data.data;
                        var replyContainer = document.getElementById('replyContainer');
                         if(page === 1){
                         replyContainer.innerHTML = '<br><br>全部讨论（'+responseData.data.total+'）回复<br><br>';
                    }

                        if (!replyContainer && page === 1) {
                            if (booklistsContainer) {
                                var booklistsContainer = document.querySelector('.booklists');
                                replyContainer = document.createElement('div');
                                replyContainer.id = 'replyContainer';
                                booklistsContainer.appendChild(replyContainer);

                                if (responseData.data.page_count > 1) {
                                    var loadMoreHTML = '<div id="loadMore" class="loading">' +
                                        '<span class="loading-text">点击加载更多评论</span>' +
                                        '</div>' +
                                        '<div id="loadingIndicator" class="loading hidden">' +
                                        '加载中...' +
                                        '</div>' +
                                        '<div id="noMore" class="loading hidden">' +
                                        '已加载所有评论' +
                                        '</div>';
                                    var loadMoreContainer = document.createElement('div');
                                    loadMoreContainer.innerHTML = loadMoreHTML;
                                    booklistsContainer.appendChild(loadMoreContainer);
                                }
                            } else {
                                console.error("找不到书籍列表容器");
                                return;
                            }
                        }

                        if (replyContainer) {
                            var startFloor = (page - 1) * 20; 
                            for (var i = 0; i < replies.length; i++) {
                                var replyItem = replies[i];
                                var floor = startFloor + i + 1;
                                let onclickOpen = \` onclick="openS('$\{replyItem.nickname}','$\{replyItem.readerid}')"\`;
                                replyContainer.innerHTML += '<div class="comment">' +
                                '<span style="color:#3A9DBF"'+onclickOpen+'>' + floor + '楼 '+replyItem.nickname+'</span><br>' + 
                                replaceEmoticons(replyItem.body || '') + 
                                '</div>'+getBooklist(replyItem)+"<br><br>"
                            }

                            if (page === 1) {
                                replyManager.totalPages = responseData.data.page_count;
                                replyManager.listid = listid;
                                replyManager.currentPage = 1;
                                replyManager.isInitialized = true;

                                var loadingIndicator = document.getElementById('loadingIndicator');
                                if (loadingIndicator) loadingIndicator.classList.add('hidden');

                                if (replyManager.totalPages > 1) {
                                    var loadMoreBtn = document.getElementById('loadMore');
                                    if (loadMoreBtn) {
                                        loadMoreBtn.classList.remove('hidden');
                                        loadMoreBtn.querySelector('.loading-text').textContent = "点击加载更多评论 (第2/" + replyManager.totalPages + "页)";
                                        loadMoreBtn.onclick = function() { loadReplies(2); };
                                    }
                                }
                            } else {
                                replyManager.currentPage = page;

                                var loadingIndicator = document.getElementById('loadingIndicator');
                                var loadMoreBtn = document.getElementById('loadMore');
                                var noMore = document.getElementById('noMore');

                                if (loadingIndicator) loadingIndicator.classList.add('hidden');

                                if (replyManager.currentPage >= replyManager.totalPages) {
                                    if (noMore) noMore.classList.remove('hidden');
                                } else {
                                    if (loadMoreBtn) {
                                        loadMoreBtn.classList.remove('hidden');
                                        loadMoreBtn.querySelector('.loading-text').textContent = "点击加载更多评论 (第" + (replyManager.currentPage + 1) + "/" + replyManager.totalPages + "页)";
                                        loadMoreBtn.onclick = function() { loadReplies(replyManager.currentPage + 1); };
                                    }
                                }
                            }
                        }
                    } else {
                        throw new Error('数据格式错误');
                    }

                } catch (e) {
                    throw new Error('解析数据失败: ' + e.message);
                }
            })
            .catch(function(error) {
                console.error('加载评论失败:', error);
                showError("加载失败，点击重试", page);
            })
            .finally(function() {
                replyManager.isLoading = false;
            });
    }

    function showError(message, page) {
        if (page === 1) {
            var loadingIndicator = document.getElementById('loadingIndicator');
            if (loadingIndicator) {
                loadingIndicator.innerHTML = '<span class="loading-error">' + message + '</span>';
                loadingIndicator.onclick = function() {
                    loadingIndicator.innerHTML = '加载中...';
                    loadingIndicator.onclick = null;
                    loadReplies(page);
                };
            }
        } else {
            var loadMoreBtn = document.getElementById('loadMore');
            if (loadMoreBtn) {
                loadMoreBtn.innerHTML = '<span class="loading-error">' + message + '</span>';
                loadMoreBtn.classList.remove('hidden');
                loadMoreBtn.onclick = function() {
                    loadMoreBtn.innerHTML = '<span class="loading-text">点击加载更多评论</span>';
                    loadMoreBtn.onclick = function() { loadReplies(page); };
                    loadReplies(page);
                };
            }
        }
    }

    window.addShelf = function(bookid) {
        var booksrc = "https://app-cdn.jjwxc.net/androidapi/novelbasicinfo?novelId=" + bookid;
        booksrc = "legado://import/addToBookshelf?src=" + encodeURIComponent(booksrc);
        window.open(booksrc);
    };

    function init() {
        if (window.location.href.includes('subjectDetail')) {
            var booklistsContainer = document.querySelector('.booklists');
            if (booklistsContainer) {
                var replyContainer = document.createElement('div');
                replyContainer.id = 'replyContainer';
                booklistsContainer.appendChild(replyContainer);

                var loadingIndicator = document.createElement('div');
                loadingIndicator.id = 'loadingIndicator';
                loadingIndicator.className = 'loading';
                loadingIndicator.innerHTML = '正在加载评论...';
                booklistsContainer.appendChild(loadingIndicator);
                loadReplies(1);
                var isScrolling = false;
                window.addEventListener('scroll', function() {
                    if (isScrolling || replyManager.isLoading || !replyManager.isInitialized || replyManager.currentPage >= replyManager.totalPages) {
