function generateFinalUrl(formData) {
    const variables = {};
    for (let [key, value] of formData.entries()) {
        const variableName = key.replace(/\d+/g, '');
        if (!variables[variableName]) {
            variables[variableName] = [];
        }
        variables[variableName].push(value);
    }

    for (const key in variables) {
        variables[key] = variables[key].join(',');
    }

    let bookurl = `https://android.jjwxc.net/search/getSearchForKeyWords?offset=0&limit=20&bq=${variables.bq || ''}&removetags=${variables.removebq || ''}&notlikecollectionTypes=${variables.notlikecollectiontypes || ''}&fw=${variables.fw || ''}&yc=${variables.yc || ''}&xx=${variables.xx || ''}&sd=${variables.sd || ''}&lx=${variables.lx || ''}&mainview=${variables.mainview || ''}&fbsj=${variables.fbsj || ''}&novelbefavoritedcount=${variables.novelbefavoritedcount || ''}&isfinish=${variables.isfinish || ''}&collectionTypes=${variables.collectiontypes || ''}&searchkeyWords=${variables.searchkeywords || ''}&sortType=${variables.sorttype}`;
    return bookurl
}

