function login() {
    let bgColor = String(result["背景#RGB格式"]);
    const rgbRegex = /^#([0-9A-Fa-f]{3,8})$/;
    if (rgbRegex.test(bgColor)) {
        cache.put("_BACK_GROUND_COLOR_", bgColor);
        java.log(`当前背景：${bgColor}`);
        java.toast(`当前背景：${bgColor}`);
    } else {
        java.log("颜色格式不合法");
        java.toast("颜色格式不合法");
    }
}
function setTheme() {
    if (cache.get("_BACK_GROUND_COLOR_") == "floralwhite") {
        cache.put("_BACK_GROUND_COLOR_", "#151924");
        java.toast("当前暗色主题");
    }
    else {
        cache.put("_BACK_GROUND_COLOR_", "floralwhite");
        java.toast("当前亮色主题");
    }
}
function logT(n) {
    if (n == 1) {
        let zy = cache.get("_PICTURE_MARGIN_LEFT_RIGHT_") || 95;
        java.toast(`图片左右页边距：${100 - zy}%`);
    }
    else if (n == 2) {
        let sx = cache.get("_PICTURE_MARGIN_TOP_BOTTOM_") || 10;
        java.toast(`图片上下间距：${sx}px`);
    }
    else if (n == 3) {
        let yj = cache.get("_PICTURE_BORDER_RADIUS_") || 10;
        java.toast(`图片圆角：${yj}px`);
    }
}
function zuoyou(n) {
    let zy = cache.get("_PICTURE_MARGIN_LEFT_RIGHT_") || 95;
    if (n === 0) {
        zy++;
        if (zy > 100) {
            zy = 100;
        }
    } else {
        zy--;
        if (zy < 0) {
            zy = 0;
        }
    }
    cache.put("_PICTURE_MARGIN_LEFT_RIGHT_", zy);
    if (zy === 100) {
        java.toast("无页边距");
    } else if (zy === 0) {
        java.toast("不能为100%");
    } else {
        java.toast(`图片左右页边距：${100 - zy}%`);
    }
}
function shangxia(n) {
    let sx = cache.get("_PICTURE_MARGIN_TOP_BOTTOM_") || 10;
    if (n == 0) {
        sx--;
        if (sx < 0) {
            sx = 0;
            cache.put("_PICTURE_MARGIN_TOP_BOTTOM_", sx);
            java.toast("间距不能小于0px");
        }
        else {
            cache.put("_PICTURE_MARGIN_TOP_BOTTOM_", sx);
            java.toast(`图片上下间距：${sx}px`);
        }
    }
    else {
        sx++;
