@js:
var doc = org.jsoup.Jsoup.parse(result);
var html = "";

// ========== 1. 简介部分 (增强兼容性) ==========
var titleEle = doc.select("h1.entry-title, h2.single-post-title, .post-title").first();
var tagsEle = doc.select("div.post-tags, .entry-meta, .tags-links").first();

if (titleEle) {
    html += "<h2 style='font-size: 1.2em; font-weight: bold; margin: 10px 0;'>" + titleEle.text() + "</h2>";
}
if (tagsEle) {
    html += "<div style='color: #666; font-size: 0.85em; margin-bottom: 10px;'>" + tagsEle.html() + "</div>";
}
html += "<hr style='border: 0; height: 1px; background: #eee; margin: 15px 0;'>";

// ========== 2. 正文图片 (保持之前的去噪逻辑) ==========
var entry = doc.select("div.entry-content, article .post-content, #content");
var imgs = entry.select("img");

for (var i = 0; i < imgs.size(); i++) {
    var img = imgs.get(i);
    var realSrc = img.attr("data-lazy-src") || img.attr("data-src") || img.attr("data-original") || img.attr("src");

    if (realSrc && !realSrc.startsWith("data:image") && !realSrc.includes("avatar") && realSrc.startsWith("http")) {
        html += "<img src='" + realSrc + "' style='display:block; width:100%; margin:0; padding:0;' />";
    }
}

// ========== 3. 相关推荐 (修复超链接和标题丢失问题) ==========
var relatedSection = doc.select("section#related-posts, .related-posts");
if (relatedSection.size() > 0) {
    html += "<hr><h3 style='text-align:center; font-size: 16px; margin: 20px 0;'>YOU MIGHT ALSO LIKE</h3>";

    // 这里的选择器必须精准覆盖到每一项
    var items = relatedSection.select("article, .related-post");
    for (var j = 0; j < items.size(); j++) {
        var item = items.get(j);

        // 提取链接：优先找 a 标签
        var aTag = item.select("a").first();
        var link = aTag ? aTag.attr("abs:href") : ""; // 使用 abs:href 获取绝对路径

        // 提取图片
        var rImg = item.select("img").first();
        var rSrc = "";
        if (rImg) {
            rSrc = rImg.attr("data-lazy-src") || rImg.attr("data-src") || rImg.attr("src");
        }

        // 提取标题：多渠道寻找标题文本
        var rTitle = item.select(".related-post-title, h4, .post-title").text() || (aTag ? aTag.attr("title") : "");

        // 重新拼接 HTML：确保 a 标签包裹整个区域
        if (link && (rSrc || rTitle)) {
            html += "<div style='margin-bottom: 25px; text-align: center; border: 1px solid #f0f0f0; padding: 10px; border-radius: 8px;'>";
            html += "  <a href='" + link + "' style='text-decoration: none; color: #333;'>";
            if (rSrc && !rSrc.startsWith("data:image")) {
                html += "    <img src='" + rSrc + "' style='width:100%; border-radius: 4px; margin-bottom: 8px;' />";
            }
            if (rTitle) {
                html += "    <div style='font-size: 14px; font-weight: 500; line-height: 1.4;'>" + rTitle + "</div>";
            }
            html += "  </a>";
            html += "</div>";
        }
    }
}

html;

