    .split('_')
    .map(c => parseInt(c, 10));

  var ivBytes = "57_55_98_54_48_51_57_52_97_98_99_50_102_98_101_49"
    .split('_')
    .map(c => parseInt(c, 10));

  return java.createSymmetricCrypto(
    "AES/CBC/PKCS5Padding", 
    keyBytes,
    ivBytes
  ).decrypt(result);
})();

