    video.setAttribute('data-rotation', newRotation);
    video.style.transform = `rotate(${newRotation}deg) scale(${video.style.transform.match(/scale\(([^)]+)\)/)?.[1] || 1})`;
}, { horizontal: 'right' });

// 缩放按钮
let zoomCount = 0;
createButton('+', () => {
    const currentTransform = video.style.transform || 'rotate(0deg) scale(1)';
    const scale = parseFloat(currentTransform.match(/scale\(([^)]+)\)/)?.[1] || 1);
    const newScale = zoomCount < 4 ? scale * 1.25 : 1;
    zoomCount = zoomCount < 4 ? zoomCount + 1 : 0;
    video.style.transform = `rotate(${video.getAttribute('data-rotation') || 0}deg) scale(${newScale})`;
}, { horizontal: 'left' });

